106	function policyPremium(step: Step, isFollowUp: boolean): number {
107	  const items = step.items ?? [];
108	  const base = basePremium(items);
109	  const surcharges = surchargePremium(items);
110	  if (step.customer === undefined) {
111	    return base + surcharges;
112	  }
113	  const loyaltyDiscount = isLoyal(step.customer) ? LOYALTY_DISCOUNT : 0;
114	  const followUpDiscount = isFollowUp ? FOLLOW_UP_DISCOUNT : 0;
115	  const netModifierRate =
116	    FIRST_INSURANCE_SURCHARGE - loyaltyDiscount - followUpDiscount;
117	  return base + surcharges + base * netModifierRate;
