146	function damagePayout(item: Item | undefined, amount: number): number {
147	  const coveredAmount =
148	    (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
149	      ? amount * HIGH_ENCHANTMENT_REIMBURSEMENT
150	      : amount;
151	  return coveredAmount - DEDUCTIBLE;
152	}
