154	function claimResult(
155	  step: Step,
156	  steps: Step[],
157	  consumedByPolicy: Map<number, number>,
158	): { payout: number; remainingCap: number } {
159	  const policyIndex = step.policy ?? 0;
160	  const policyStep = steps[policyIndex];
161	  const policyItems = policyStep.items ?? [];
162	  const cap = CAP_MULTIPLIER * insuranceSum(policyItems);
163	  const damages = step.incident?.damages ?? [];
164	  const desiredPayout = damages.reduce((total, damage) => {
165	    const item = policyItems.find((i) => i.type === damage.itemType);
166	    return total + damagePayout(item, damage.amount);
167	  }, 0);
168	  const consumed = consumedByPolicy.get(policyIndex) ?? 0;
169	  const availableCap = cap - consumed;
170	  const payout = roundDownInFavor(Math.min(desiredPayout, availableCap));
171	  consumedByPolicy.set(policyIndex, consumed + payout);
172	  return { payout, remainingCap: availableCap - payout };
173	}
174	
175	function hasPriorQuote(steps: Step[], index: number): boolean {
176	  return steps.slice(0, index).some((prior) => prior.type === "quote");
177	}
