179	export function runScenario(steps: Step[]): unknown[] {
180	  const consumedByPolicy = new Map<number, number>();
181	  return steps.map((step, index) => {
182	    if (step.type === "claim") {
183	      return claimResult(step, steps, consumedByPolicy);
184	    }
185	    return quoteResult(step, hasPriorQuote(steps, index));
186	  });
187	}
